@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.Web.ExcludeFromInteractiveRouting]
@using Microsoft.AspNetCore.Http

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>Your privacy is important to us. This page describes how we handle your data.</p>

@if (_hasConsent)
{
    <div class="alert alert-success">
        ✓ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        You have not yet accepted our cookie policy.
    </div>
}

@code {
    private bool _hasConsent;

    [CascadingParameter]
    public HttpContext? HttpContext { get; set; }

    protected override void OnInitialized()
    {
        if (HttpContext is not null)
        {
            _hasConsent = HttpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

